
    INSERT INTO products (
      id, name, category, category_label, price, original_price, rating, review_count, 
      description, features, images, shapes, sizes, colors, tags, in_stock, best_seller, new_arrival
    ) VALUES (
      'press-on-chandni-pearl', 'Chandni Pearl Glazed Set', 'press-on', 'Press-On Nails', 
      599, 749, 4.9, 342, 
      'Get that dreamy desi-chic chrome pearl finish inspired by moonlit Indian weddings. These salon-quality reusable press-on nails give you a signature bridal glow in under 10 minutes — perfect for shaadi season, Karva Chauth, or Diwali parties.', '["Reusable up to 5 times with proper care","Non-damaging salon-grade adhesive tabs & liquid glue included","Ultra-flex technology for comfortable, seamless natural fit on Indian nail beds","Waterproof and chip-resistant coating — survives mehendi, haldi & kitchen work"]'::jsonb, '["https://images.pexels.com/photos/10609757/pexels-photo-10609757.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=1200&w=800","https://images.pexels.com/photos/2281695/pexels-photo-2281695.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=1200&w=800","https://images.pexels.com/photos/5484948/pexels-photo-5484948.png?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200"]'::jsonb, '["Almond","Oval","Coffin"]'::jsonb, 
      '["XS","S","M","L","Custom"]'::jsonb, NULL, '["glazed","chrome","nude","bridal","wedding"]'::jsonb, TRUE, 
      TRUE, FALSE
    );
  
    INSERT INTO products (
      id, name, category, category_label, price, original_price, rating, review_count, 
      description, features, images, shapes, sizes, colors, tags, in_stock, best_seller, new_arrival
    ) VALUES (
      'press-on-shaadi-maroon', 'Shaadi Special Maroon Set', 'press-on', 'Press-On Nails', 
      499, NULL, 4.8, 278, 
      'Deep, rich maroon that matches your bridal lehenga perfectly. This luxurious dark tone offers ultimate sophistication for Indian weddings, sangeet nights, and festive celebrations. Designed in a high-gloss gel finish that looks freshly done at a premium Mumbai salon.', '["Stays vibrant and glossy for up to 2 weeks through Indian festivities","Includes prep pad, cuticle pusher, and nail file","Eco-friendly materials, cruelty-free and vegan formula","Custom sizing templates to ensure perfect fit for Indian hands"]'::jsonb, '["https://images.pexels.com/photos/2281695/pexels-photo-2281695.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=1200&w=800","https://images.pexels.com/photos/10609757/pexels-photo-10609757.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=1200&w=800"]'::jsonb, '["Almond","Coffin","Square"]'::jsonb, 
      '["XS","S","M","L"]'::jsonb, NULL, '["bridal","maroon","wedding","festive","karva-chauth"]'::jsonb, TRUE, 
      TRUE, TRUE
    );
  
    INSERT INTO products (
      id, name, category, category_label, price, original_price, rating, review_count, 
      description, features, images, shapes, sizes, colors, tags, in_stock, best_seller, new_arrival
    ) VALUES (
      'press-on-desi-french', 'Desi French Tip Set', 'press-on', 'Press-On Nails', 
      549, 699, 4.7, 214, 
      'A contemporary desi take on the timeless French manicure. Features micro-fine pastel tips over a flawless translucent peach base that complements Indian wheatish to dusky skin tones beautifully. Perfect for everyday office wear, college, or subtle bridal looks.', '["Double UV-cured gel surface coating","Slightly curved design fits Indian nailbeds perfectly","Includes both temporary gel tabs and extra strength 14-day glue","Zero fading, zero chipping, vegan-friendly plastic formulation"]'::jsonb, '["https://images.pexels.com/photos/5484948/pexels-photo-5484948.png?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200","https://images.pexels.com/photos/6135681/pexels-photo-6135681.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200"]'::jsonb, '["Almond","Oval","Square"]'::jsonb, 
      '["XS","S","M","L"]'::jsonb, NULL, '["french-tip","office-wear","minimal","daily-wear"]'::jsonb, TRUE, 
      FALSE, FALSE
    );
  
    INSERT INTO products (
      id, name, category, category_label, price, original_price, rating, review_count, 
