    ) VALUES (
      'press-on-hariyali-velvet', 'Hariyali Velvet Cat Eye', 'press-on', 'Press-On Nails', 
      649, NULL, 5, 167, 
      'Inspired by the lush greens of the Indian monsoon. These stunning deep emerald press-ons reflect light at every angle, creating a mesmerizing cat-eye shimmer that shifts dynamically — perfect for Teej, Eid, or a bold statement at cocktail parties.', '["Premium magnetic gel coating for deep 3D velvet effect","Thicker reinforced tips prevent bending and splitting","Fits comfortably like a custom salon acrylic set","Contains 30 nails in 15 sizes per set to ensure complete fit"]'::jsonb, '["https://images.pexels.com/photos/10592995/pexels-photo-10592995.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200","https://images.pexels.com/photos/7755287/pexels-photo-7755287.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200"]'::jsonb, '["Coffin","Almond","Stiletto"]'::jsonb, 
      '["S","M","L"]'::jsonb, NULL, '["cat-eye","velvet","magnetic","green","festive"]'::jsonb, TRUE, 
      FALSE, TRUE
    );
  
    INSERT INTO products (
      id, name, category, category_label, price, original_price, rating, review_count, 
