    ) VALUES (
      'polish-gulaabi-nude', 'Gulaabi Nude Gel Polish', 'polish', 'Gel Polish', 
      349, 449, 4.6, 198, 
      'The ultimate sheer pinkish-nude gel polish specially formulated for Indian skin tones. This self-leveling, highly pigmented formula gives you streak-free coverage in just two thin coats — from fair to deep dusky complexions.', '["Professional grade HEMA-free formula safe for Indian nails","Cures in just 60 seconds under LED/UV lamps","Up to 21 days of high-shine wear without lifting in humid Indian weather","Cruelty-free, vegan, and 10-free certified toxin free"]'::jsonb, '["https://images.pexels.com/photos/12571010/pexels-photo-12571010.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=1200&w=800","https://images.pexels.com/photos/20849460/pexels-photo-20849460.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=1200&w=800"]'::jsonb, NULL, 
      NULL, '[{"name":"Soft Peach Blush","hex":"#ffdcd2"},{"name":"Warm Nude Dune","hex":"#e8cbb6"},{"name":"Milky Coconut","hex":"#fdfcf7"}]'::jsonb, '["gel-polish","nude","sheer","indian-skin","daily"]'::jsonb, TRUE, 
      TRUE, FALSE
    );
  
